import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - Next Generation", () => {
  it.todo("should return empty array when given empty array");
  it.todo("should kill a single live cell with no neighbors (underpopulation)");
  it.todo("should kill live cells when each has only 1 neighbor (underpopulation)");
  it.todo("should keep a live cell alive when it has 2 live neighbors (survival)");
  it.todo("should keep a live cell alive when it has 3 live neighbors (survival)");
  it.todo("should kill a live cell when it has more than 3 live neighbors (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
  it.todo("should transform a vertical blinker into a horizontal blinker");
  it.todo("should keep a block pattern unchanged (still life)");
});
